"use client";

import { Container } from "@/components/layout/Container";
import { NavLink } from "@/components/ui/NavLink";
import type { NavItem } from "@/content/site";
import { useSyncExternalStore } from "react";

type SiteHeaderProps = {
  brandName: string;
  navigation: NavItem[];
};

/** Section DOM ids in scroll order; maps to nav href for scroll-spy. */
const SCROLL_IDS = ["top", "services", "samples", "about", "contact"] as const;

/** Which nav `href` is active while a section id is in view (samples → Voice work). */
const SECTION_NAV_HREF: Record<(typeof SCROLL_IDS)[number], string> = {
  top: "#top",
  services: "#services",
  samples: "#services",
  about: "#about",
  contact: "#contact",
};

function activeNavHrefFromScroll(): string {
  if (typeof document === "undefined") return "#top";

  const header = document.querySelector<HTMLElement>("[data-site-header]");
  const headerH = header?.offsetHeight ?? 72;
  const y = window.scrollY + headerH + 24;

  let current: (typeof SCROLL_IDS)[number] = "top";
  for (const id of SCROLL_IDS) {
    const el = document.getElementById(id);
    if (!el) continue;
    const top = el.getBoundingClientRect().top + window.scrollY;
    if (y >= top) current = id;
  }
  return SECTION_NAV_HREF[current];
}

function subscribeNavHref(cb: () => void) {
  const run = () => cb();
  window.addEventListener("scroll", run, { passive: true });
  window.addEventListener("resize", run);
  queueMicrotask(run);
  return () => {
    window.removeEventListener("scroll", run);
    window.removeEventListener("resize", run);
  };
}

function useActiveNavHref(): string {
  return useSyncExternalStore(
    subscribeNavHref,
    activeNavHrefFromScroll,
    () => "#top",
  );
}

function HeaderNavList({
  items,
  activeHref,
  className,
}: {
  items: NavItem[];
  activeHref: string;
  className?: string;
}) {
  return (
    <ul className={className}>
      {items.map((item) => (
        <li key={item.href + item.label}>
          <NavLink
            href={item.href}
            variant="header"
            active={item.href === activeHref}
            className="text-small"
          >
            {item.label}
          </NavLink>
        </li>
      ))}
    </ul>
  );
}

